// package-lock-generator.js

const fs = require('fs');
const path = require('path');
const npmLs = require('npm-ls');

function generatePackageLock() {
  const pkgFile = 'package.json';
  const lockFile = 'package-lock.json';

  if (fs.existsSync(lockFile)) {
    console.log(`package-lock.json already exists, skipping generation.`);
    return;
  }

  try {
    const packageData = require(pkgFile);
    npmLs(packageData, (err, data) => {
      if (err) {
        throw err;
      }
      fs.writeFileSync(lockFile, JSON.stringify(data));
      console.log(`package-lock.json generated successfully!`);
    });
  } catch (err) {
    console.error(err);
  }
}

module.exports = generatePackageLock;

